function OnGetVariableRequestId()
{
	// <remarks>Caller is responsible to catch exceptions</remarks>

	var val = null;

	if (JsIsFeatureEnabled("divRequestIdArea"))
	{
		try
		{
			val = external.JsGetRequestId(0);
		}
		catch (ex)
		{
			// For old Agent which doesn't support JsGetRequestId call we will request variable.
			val = external.JsOnGetVariable("VF_GENERATED_REQUEST_ID");
		}
	}

	if (JsIsFeatureEnabled("divFileIdArea"))
	{
		try
		{
			var inputMask = document.getElementById("LongRequestFieldsMask");
			var mask = (inputMask != null) ? parseInt(inputMask.value) : 1;
			val = external.JsGetRequestId(mask);
		}
		catch (ex)
		{
			// For old Agent which doesn't support JsGetRequestId call we will request variable.
			val = external.JsOnGetVariable("VF_GENERATED_FILE_ID");
		}
	}

	return val;  
}

function JsGetDocumentSize()
{
	function Size()
	{
		this.Width  = 0;
		this.Height = 0;
	}

	var docSize = new Size();
	var right  = 0;
	var bottom = 0;
	var isMacDialog = false;

	for (var i = 0; i < document.all.length; i++) 
	{
		var child = document.all[i];

		var tagName = child.tagName.toLowerCase();
		if (tagName == "html" || tagName == "body" || tagName == "form")
			continue;

		var id = child.getAttribute("id");
		if (id == "imgBackground" || id == "imgTitleBackground")
			continue;

		var className = child.getAttribute("className");
		if (/* still */ className == null)
			className = child.getAttribute("class");
		if (className != null)
		{
			if (className.indexOf("WatermarkImage")   > -1 ||
                className.indexOf("WatermarkContent") > -1 ||
                className.indexOf("TitleBackground")  > -1)
			{
				continue;
			}
		}

		if (className === "mac-thematic-break") isMacDialog = true;

		right = child.offsetLeft + child.offsetWidth;
		if (right > docSize.Width) 
			docSize.Width = right;

		bottom = child.offsetTop + child.offsetHeight;
		if (bottom > docSize.Height) 
			docSize.Height = bottom;
	}

	var declaredWidth = getDeclaredDialogWidth();
	if (declaredWidth > 0)
		docSize.Width = declaredWidth;
	if (isMacDialog)
	{
		if (docSize.Height > 625) docSize.Height = 625;
		if (docSize.Width > 580) docSize.Width = 580;
	}
	return docSize;
}

var DialogWidth = 0;

function fitLine(ctrl, text)
{
	return text;    // Temporary cancel fitLine because it break href's

	var charCountToFit = 35;

	try
	{  
		// Try to detect actual value of charCountToFit

		if (DialogWidth == 0)
			DialogWidth = getDeclaredDialogWidth();

		var currentStyle = getDomElementCurrentStyle(ctrl);
		var bounds       = getBoundingClientRect(ctrl);

		if (currentStyle != null && bounds != null && DialogWidth > 0)
		{
			var ctrlWidth       = DialogWidth - Math.round(bounds.left);
			var fontSize        = parseInt(currentStyle.fontSize);
			var avgCharWidth    = Math.round(fontSize * 2 / 3);

			charCountToFit      = Math.round(ctrlWidth / avgCharWidth);    
		}
	}
	catch(ex) { }

	try
	{
		if (text.length > charCountToFit)
		{
			text = breakLine(text, charCountToFit, /* useHyphen = */ false);
		}
	}
	catch(ex) { }

	return text;
}

function breakLine(source, lineLength, useHyphen)
{
	/// <summary>
	/// Breaks long string to several lines in order to fit inside some rectangle.
	/// </summary>
	/// <param name="source"     type="string" optional="false">String to break</param>
	/// <param name="lineLength" type="number" optional="true">Max line length</param>
	/// <param name="useHyphen"  type="boolean" optional="true">Indicates whether Hyphen (-) should be used on line break.</param>

	if (typeof (lineLength) == "undefined") lineLength = 70;
	if (typeof (useHyphen)  == "undefined") useHyphen = true;

	var res = "";

	try
	{
		var continuousCount = 0;
		var isBreaked = false;
		var breakTags = ["<br>", "<br />", "<br/>"];

		for (var k = 0; k < source.length; k++)
		{
			isBreaked = false;

			var ch = source.charAt(k);
			if (ch == " ")
			{
				continuousCount = 0;
				isBreaked = true;
			}

			if (ch == "<")
			{
				// We shouldn't break inside valid HTML line break tags (for example, "<br>")

				for (var i = 0; i < breakTags.length; i++)
				{
					var tag = breakTags[i];

					if (k + tag.length <= source.length && source.substr(k, tag.length).toLowerCase() == tag)
					{
						continuousCount = 0;
						isBreaked = true;
						break;
					}
				}
			}

			if (!isBreaked)
				continuousCount++;

			if (continuousCount == lineLength)
			{
				if (useHyphen)
					res += "-";
				res += "<br>";
				continuousCount = 0;
			}

			res += ch;
		}
	}
	catch (ex)
	{
		res = source;
	}

	return res;
}

function getDomElementCurrentStyle(elem)
{
	/// <summary>
	/// Gets HTML Element current style (i.e.considering all styles defining in element itself, ingerited from parent elements or specifying in CSS classes).
	/// </summary>
	/// <param name="elem">HTML element</param>
	/// <returns>Style object or null when some error has been occurred</returns>

	try
	{
		if (typeof(elem) == "undefined" || elem == null)
			return null;

		if (typeof(elem.currentStyle) != "undefined" && elem.currentStyle != null)
		{
			return elem.currentStyle;
		}

		else if (typeof(window.getComputedStyle) != "undefined")
		{
			window.getComputedStyle(elem);
		}

		else
			return null;

	}
	catch (ex)
	{
		return null;
	}
}

function getBoundingClientRect(elem)
{
	/// <summary>
	/// Gets DOM Element bounding rectangle.
	/// </summary>
	/// <param name="elem">DOM element</param>
	/// <returns>DOM Element bounding rectangle or null when some error has been occurred</returns>    

	try
	{
		if (typeof(elem) == "undefined" || elem == null)
			return null;

		if (typeof(elem.getBoundingClientRect) != "undefined")
			return elem.getBoundingClientRect();
		else
			return null;
	}
	catch(ex)
	{
		return null;
	}
}

function getDeclaredDialogWidth()
{
	/// <summary>
	/// Gets Dialog width as declared in "DialogWidth" CSS class.
	/// </summary>    

	var dialogWidth = 0;

	try
	{
		for (var i = 0; i < document.styleSheets.length; i++)
		{
			var styleSheet = document.styleSheets[i];   // Instance of CSSStyleSheet class. Presenting separate StyleSheet (i.e. each <style>...</style> or <link ... /> block)
			if (styleSheet != null)
			{
				if (typeof(styleSheet.cssText) != "undefined" && typeof(styleSheet.cssText.indexOf) != "undefined")	// IE has "cssText" property while Chrome doesn't have.
				{
					if (styleSheet.cssText.indexOf("DialogWidth") == -1)
						continue;
				}

				var cssRules = null;
				if (typeof(styleSheet.cssRules) != "undefined")
					cssRules = styleSheet.cssRules;
				else if (typeof(styleSheet.rules) != "undefined")
					cssRules = styleSheet.rules;

				if (cssRules != null)
				{
					for (var j = 0; j < cssRules.length; j++)
					{
						var cssRule = cssRules[j];   // Instance of CSSStyleRule class. Presenting separate CSS class inside StyleSheet.
						if (cssRule != null && cssRule.selectorText.indexOf("DialogWidth") > -1)
						{
							dialogWidth = parseInt(cssRule.style.width, /* radix = */ 10);
							break;
						}
					}
				}
			}

			if (dialogWidth > 0)
				break;
		}
	}
	catch(ex)
	{
		dialogWidth = 0;
	}

	return dialogWidth;
}

function AddCssToHtml(id, url)
{
	var objHead = document.getElementsByTagName("head")[0];
	var objCSS = document.createElement("link");
	objCSS.setAttribute("id", id);
	objCSS.setAttribute("rel", "stylesheet");
	objCSS.setAttribute("type", "text/css");
	objCSS.setAttribute("href", url);
	objHead.appendChild(objCSS);
}

// WARNING! Do not change lines with the following constants:
// "s" + "c" + "r" + "i" + "p" + "t" and "s" + "r" + "c"
// Regular expressions is doing bad work...
function AddJsToHtml(id, url)
{
	var objHead = document.getElementsByTagName("head")[0];
	var objJS = document.createElement("s" + "c" + "r" + "i" + "p" + "t");
	objJS.setAttribute("id", id);
	objJS.setAttribute("s" + "r" + "c", url);
	objHead.appendChild(objJS);
}

function InitIdaptiveWidget(btnOK)
{
	var divIdaptiveArea = document.getElementById("divIdaptiveArea");
	var divIdaptiveForm = document.getElementById("divIdaptiveForm");
	// EPM-17170 - Adding enforce flag in identity dialog and implement it accordingly
	var txtIdaptiveForceUsername = document.getElementById("IdaptiveForceUsername");

	if (divIdaptiveArea != null && divIdaptiveArea.style.display != "none" && divIdaptiveForm != null)
	{
		divIdaptiveForm.className = "Loading";
		divIdaptiveForm.innerHTML = "<div style=\"padding-top: 35px\">Loading Idira Identity Authentication...</div>";

		if (typeof (btnOK) != "undefined" && btnOK != null)
			btnOK.setAttribute("disabled", "disable");

		// IMPORTANT! The order of the requirements check up has to be following:
		// 1. Check up agent's ability to work with Ipdative - agent's version
		// 2. Check up browser's emulation version
		// This is because we had not browser's emulation increasing for old agents
		// and we will see "old browser version" message for both cases

		// 1. Check up agent ability to return config parameter by name - agent's version check up
		var tenantId = "";
		var widgetTimeout = 10;
		try
		{
			tenantId = external.JsOnGetAgentConfigValue("IdaptiveIntegration/IdaptiveTenantId");
			widgetTimeout = parseInt(external.JsOnGetAgentConfigValue("IdaptiveIntegration/IdaptiveTimeout"));
			if (isNaN(widgetTimeout))
				widgetTimeout = 10;
		}
		catch (ex)
		{
			var message = "<b>Unable to load Idira Identity Authentication.</b><br />";
			message += "Contact IT support to upgrade the EPM agent on your endpoint.";
			divIdaptiveForm.className = "Error";
			divIdaptiveForm.innerHTML = message;
			return;
		}

		// 2. Check browser's emulation version
		var ieVersion = DetectIEVersion();
		if (typeof (ieVersion) != "number" || ieVersion < 11)
		{
			var message = "<b>Unable to load Idira Identity Authentication.</b><br />";
			message += "Contact IT support to upgrade your Internet browser.";
			divIdaptiveForm.className = "Error";
			divIdaptiveForm.innerHTML = message;
			return;
		}

		if (typeof (tenantId) != "string" || tenantId == null || tenantId == "")
		{
			var message = "<b>Unable to load Idira Identity Authentication.</b><br />";
			message += "Contact IT support to complete Idira Identity configuration in EPM.";
			divIdaptiveForm.className = "Error";
			divIdaptiveForm.innerHTML = message;
			return;
		}

		var isForceUserName = false;
		if (txtIdaptiveForceUsername != null)
			isForceUserName = (/true/i).test(txtIdaptiveForceUsername.value);

		try
		{
			var urlIdaptiveCSS = "http://" + tenantId + "/vfslow/lib/uibuild/standalonelogin/css/login.css";
			var urlIdaptiveJS = "http://" + tenantId + "/vfslow/lib/uibuild/standalonelogin/login.js";
			var urlIdaptiveGetOneTimePassword = "https://" + tenantId + "/Security/GetOneTimePassword";

			// Load Idaptive JavaScript and CSS
			var linkId = "linkIdaptiveCSS";
			var jsId = "scriptIdaptiveJS";
			if (!document.getElementById(linkId))
			{
				AddCssToHtml(linkId, urlIdaptiveCSS);
			}
			if (!document.getElementById(jsId))
			{
				AddJsToHtml(jsId, urlIdaptiveJS);
			}

			var tryCounter = 0;
			var ti = setInterval(function ()
			{
				if (typeof (LaunchLoginView) == "function")
				{
					clearInterval(ti);

					var userFromAgent = document.getElementById("lblUserName");
					var userFromAgentText = "";
					if (userFromAgent)
					{
						if ((userFromAgent.innerHTML != "<$VF_USER>") && (userFromAgent.innerHTML != "&lt;$VF_USER&gt;"))
							userFromAgentText = userFromAgent.innerHTML;
					}

					// EPM-17170 - Adding enforce flag in identity dialog and implement it accordingly
					// If isForceUserName=true but there is no UserName then try to get it from agent
					if (isForceUserName && userFromAgentText == "")
					{
						var val = external.JsOnGetVariable("VF_USER");
						// If agent returned username then use it for Idaptive auth and hide "Enter username" step
						if (type(val) == "string" && val.length > 0)
							userFromAgentText = val;
						// There is not sence to hide "Enter username" step on the Idaptive widget
						// because we did not receive username from the agent. User has to enter it.
						else
							isForceUserName = false;
					}

					LaunchLoginView({
						containerSelector: "#divIdaptiveForm",
						apiFqdn: tenantId,
						allowForgotUsername: false,
						allowRememberMe: false,
						username: userFromAgentText,
						autoSubmitUsername: isForceUserName,
						//appKey: "",
						success: function ()
						{
							LoginUtil.doPost(urlIdaptiveGetOneTimePassword, {}, function (one_time_passcode)
							{
								if (external.JsOnCheckupOneTimePasscode(one_time_passcode))
								{
									if (typeof (btnOK) != "undefined" && btnOK != null)
										btnOK.removeAttribute("disabled");

									var message = "<b>Authentication completed succesfully.</b><br />";
									message += "Click \"OK\" to continue.";
									divIdaptiveForm.className += " Info";
									divIdaptiveForm.innerHTML = message;
								}
								else
								{
									var message = "<b>Idira Identity Authentication is unable to complete.</b><br />";
									message += "Try again or contact IT support.";
									divIdaptiveForm.className += " Error";
									divIdaptiveForm.innerHTML = message;
								}
							})
						}
					});
				}
				else if (tryCounter < widgetTimeout * 2)
				{
					tryCounter = tryCounter + 1;
				}
				else
				{
					var message = "<b>Idira Identity Authentication has timed out.</b><br />";
					message += "Try again or contact IT support.";
					divIdaptiveForm.className += " Error";
					divIdaptiveForm.innerHTML = message;
					clearInterval(ti);
				}
			}, 500);
		}
		catch (ex)
		{
			var message = "<b>Unable to load Idira Identity Authentication.</b><br />";
			message += "Unexpected error: " + ex.message;
			divIdaptiveForm.className = "Error";
			divIdaptiveForm.innerHTML = message;
			if (typeof (ex.description) == "string" && ex.description != null && ex.description != "")
				message += "<br />(" + ex.description + ")";
			divIdaptiveForm.innerHTML = message;
		}
	}
}

function DetectIEVersion()
{
	var userAgent = window.navigator.userAgent;

	var msie = userAgent.indexOf('MSIE ');
	if (msie > 0)
		return parseInt(userAgent.substring(msie + 5, userAgent.indexOf('.', msie)), 10);

	var trident = userAgent.indexOf('Trident/');
	if (trident > 0)
	{
		var rv = userAgent.indexOf('rv:');
		return parseInt(userAgent.substring(rv + 3, userAgent.indexOf('.', rv)), 10);
	}

	var edge = userAgent.indexOf('Edge/');
	if (edge > 0)
		return parseInt(userAgent.substring(edge + 5, userAgent.indexOf('.', edge)), 10);

	return false;
}

function TraceInfo(message)    { Trace(ETraceLevel.INFO,    message); }
function TraceWarning(message) { Trace(ETraceLevel.WARNING, message); }
function TraceError(message)   { Trace(ETraceLevel.ERROR,   message); }

function Trace(level /*: ETraceLevel */ , message)
{
	message = "Dialog::" + message;

	try
	{
		if (external != null)
		{
			external.JsTrace(level, message); 
		}
	}  
	catch(ex) {	}  	

	TraceBrowserConsole(level, message);		
}

function TraceBrowserConsole(level /* ETraceLevel */ , message)
{
	try
	{
		var levelDisplayName = "DEBUG";
		switch (level)
		{
			case ETraceLevel.DEBUG: 	levelDisplayName = "DEBUG";		break;
			case ETraceLevel.INFO: 		levelDisplayName = "INFO";		break;
			case ETraceLevel.WARNING: 	levelDisplayName = "WARNING";	break;
			case ETraceLevel.ERROR: 	levelDisplayName = "ERROR";		break;
		}

		console.log(levelDisplayName + ": " + message);
	}
	catch(ex) {	}  	
}

