} 

var InitTimeout    = 30;
var Timeout        = 30;             // in seconds
var ActionButton   = EButtons.OK;    // Button which will be "clicked" automatically when timeout will be expired but no user action taken.
var TimerId        = -1;

var btnOKText      = "";
var btnCancelText  = "";
var btnStopNowText = "";

if (typeof(chrome) != "undefined" && chrome != null && chrome.webview != null && chrome.webview.hostObjects != null && chrome.webview.hostObjects.sync.external != null)
{
