function InitJustificationArea()
{
	try
	{
		if (JsIsFeatureEnabled("divJustificationArea"))
		{
			var options = document.getElementsByName("optJustificationOption");

			var isChecked = false;
			var isVisible = false;

			for (var i = 0; i < options.length; i++)
			{
				var opt = options[i];
				if (opt != null)
				{
					var isOptVisible = opt.style.display == null || 
                                       opt.style.display == ""   || 
                                       opt.style.display == "block";

					if (isOptVisible)
					{
						opt.checked = true;
						isChecked   = true;
						isVisible   = true;
						onJustificationOptionClick(opt.id);
						break;
					}
				}
			}

			if (!isVisible)
			{
				// When no option is visible, but entire feature is enabled 
				// suppose that only txtJustification textarea appears on the dialog.
				onJustificationOptionClick("optJustificationManual");
			}
		}
	}
	catch(ex) {}
}

function onJustificationOptionClick(optId)
{
	try
	{
		var opt = document.getElementById(optId);
		if (opt != null)
			opt.blur();

		var txtJustification = document.getElementById("txtJustification");
		if (txtJustification != null)
		{
			if (optId == "optJustificationManual")
			{
				txtJustification.disabled = false;
				txtJustification.focus();   
			}
			else
			{
				txtJustification.disabled = true;
			}
		}

	}
	catch(ex) 
	{ 
	}
}

function validateJustification()
{
	/// <summary>
	/// Returns "false" when "txtJustification" is visible but not completed by user.
	/// Otherwise "true" is returned.
	/// </summary>

	try
	{
		if (!JsIsFeatureEnabled("divJustificationArea"))
			return true;    // Entire Justification feature is disable.

		// Check by flag whether we need to perform validation.
		var needValidateJustification = true;
		var inp = document.getElementById("NeedValidateJustification");
		if (inp != null && inp.value != null)
			needValidateJustification = inp.value.toLowerCase() == "true" || inp.value == "1";  
		if (!needValidateJustification)
			return true;

		// Check whether one of visible options is checked
		var visibleOptionExists = false;
		var checkedOption = null;
		var options = document.getElementsByName("optJustificationOption");
		for (var i = 0; i < options.length; i++)
		{
			var opt = options[i];
			if (opt == null)
				continue;

			if (opt.style.display == "none")
				continue;

			visibleOptionExists = true;

			if (opt.checked)
			{
				checkedOption = opt; 
				break;
			}   
		}

		if (!visibleOptionExists)
		{
			// Even when no visible option exists, txtJustification itself can be visible.
			var txtJustification = document.getElementById("txtJustification");
			if (txtJustification == null || txtJustification.style.display == "none")
				return true;                // No visible option exists => justification should not be provided.
			else
				checkedOption = document.getElementById("optJustificationManual");
		}

		if (checkedOption == null)      // Visible option exists but no one is checked by user.
		{
			MsgBoxError("One of option must be checked");
			return false;
		}

		// When checked option is a "Manual", additionaly validate a text
		if (checkedOption.id == "optJustificationManual")
		{
			// Get min Justification length
			var minJustificationLength = null;
			inp = document.getElementById("MinJustificationLength");
			if (inp != null && inp.value != null)
				minJustificationLength = parseInt(inp.value, /* radix = */ 10);

			// Get and validate "txtJustification" content
			var txtJustification = document.getElementById("txtJustification");
			if (txtJustification == null)
				return true;
			if (txtJustification.style.display == "none")
				return true;

			var text = txtJustification.value;
			if (minJustificationLength == null)
			{
				if (text == null || text.replace(/^\s*/, "").replace(/\s*$/, "") == "")
				{
					MsgBoxError("Illegal empty justification");
					txtJustification.focus();
					return false;
				}
			}
			else
			{
				if (text == null || text.length < minJustificationLength)
				{
					MsgBoxError("Justification must be at least " + minJustificationLength + " characters long.");
					txtJustification.focus();
					return false;
				}
			}
		}

		return true;
	}
	catch (ex)
	{
		return true;
	}
}

function JsGetJustification()
{
	/// <summary>
	/// Returns string containing Justification.
	/// </summary>

	var text = "";

	var visibleOptionExists = false;
	var checkedOption = null;
	var options = document.getElementsByName("optJustificationOption");
	for (var i = 0; i < options.length; i++)
	{
		var opt = options[i];
		if (opt == null)
			continue;

		if (opt.style.display == "none")
			continue;

		visibleOptionExists = true;

		if (opt.checked)
		{
			checkedOption = opt; 
			break;
		}   
	}

	if (!visibleOptionExists)
	{
		// Even when no visible option exists, txtJustification itself can be visible.
		var txtJustification = document.getElementById("txtJustification");
		if (txtJustification == null || txtJustification.style.display == "none")
			text = "";                // No visible option exists => justification should not be provided.
		else
			checkedOption = document.getElementById("optJustificationManual");
	}

	if (checkedOption != null)
	{
		if (checkedOption.id == "optJustificationManual")
		{
			var txtJustification = document.getElementById("txtJustification");
			if (txtJustification != null)
				text = txtJustification.value;
		}
		else
		{
			var id  = "lbl" + checkedOption.id.substring(3);
			var lbl = document.getElementById(id);
			if (lbl != null)
				text = lbl.innerText;
		}
	}  

	return text;
}

function InitJustificationTypeArea()
{
    try
    {
        if (JsIsFeatureEnabled("divJustificationTypeArea"))
        {
            var optTemporary = document.getElementById("optJustificationTypeTemporary");

            // Always default to Temporary option when feature is enabled
            if (optTemporary != null)
            {
                optTemporary.checked = true;
                var defaultValue = document.getElementById("DefaultJustificationHoursLimit");
                var txtTimeLimit = document.getElementById("txtJustificationTimeLimit");
                if (txtTimeLimit != null && defaultValue != null) {
                    txtTimeLimit.addEventListener('keypress', function (e) {
                        // prevent non-numeric input
                        if (!/\d/.test(e.key)) {
                            e.preventDefault();
                        }
                    });
                    txtTimeLimit.value = defaultValue.value;
                }
                onJustificationTypeClick("optJustificationTypeTemporary");
            }
        }
    }
    catch(ex) {}
}

function onJustificationTypeClick(optId)
{
    try
    {
        var opt = document.getElementById(optId);
        if (opt != null)
            opt.blur();

        var txtTimeLimit = document.getElementById("txtJustificationTimeLimit");

        if (optId == "optJustificationTypeTemporary")
