function InitOfflineRequestArea()
{
	try
	{
		var val = OnGetVariableRequestId();
		if (val == null)
			return;

		var txtId = "";

		if (JsIsFeatureEnabled("divRequestIdArea"))
			txtId = "txtRequestId";
		else if (JsIsFeatureEnabled("divFileIdArea"))
