html, body, form
{
    height:         400px;
    font-family:    Arial;
    font-size:      14px;
    margin:         0px;
    padding:        0px;
    overflow:       hidden;
}    

.FlatTextBox
{
	border:         1px solid #b8c2c5;
	font-family:    Arial;
	font-size:      14px;
}

.FlatTextBoxHover
{
	border:         1px solid #F88104;
	font-family:    Arial;
	font-size:      14px;
}

.FlatTextBoxDisabled
{
	border-style:   solid;
	border-color:   #A9B7BE;
	border-width:   1px;
	font-family:    Arial;
