/* File version = "1.1" */

html, body, form {
	font-family: Arial;
	font-size: 14px;
	margin: 0px;
	padding: 0px;
	overflow: hidden;
}

.Status {
	border-top-width: 3px;
	border-top-style: solid;
	position: absolute;
	z-index: 999;
}

	.Status.Error {
		border-top-color: #ea112b;
		z-index: 999;
	}

	.Status.Info {
		border-top-color: #3165bd;
		z-index: 999;
	}

	.Status.Warning {
		border-top-color: #ffb135;
		z-index: 999;
	}

	.Status.Success {
		border-top-color: #14b876;
		z-index: 999;
	}

* {
	box-sizing: border-box;
	-moz-box-sizing: border-box;
	-webkit-box-sizing: border-box;
	border: none;
}

#imgLogo {
	margin-right: 20px;
}

.HeaderIcon {
	padding-right: 15px;
}

span, div, table, input, button, textarea {
	font-family: Arial;
	font-size: 14px;
	line-height: 20px;
}

table {
	border-collapse: collapse;
}

textarea {
	padding: 6px 10px 6px 10px;
	border: 1px solid #a6a6a6;
	overflow: auto;
	resize: none;
}

input.Btn,
input.Btn:visited,
input.Btn:hover,
input.Btn:focus,
input.Btn:active,
button.Btn,
button.Btn:visited,
button.Btn:hover,
button.Btn:focus,
button.Btn:active {
	border: 1px solid #3165bd;
	/*filter:chroma(color=#000000);*/
	color: #3165bd;
	background-color: #ffffff;
	text-decoration: none;
	cursor: pointer;
	width: 90px;
	height: 28px;
	margin-left: 10px;
	/*outline: none;*/
}

	input.Btn.Def,
	input.Btn.Def:visited,
	input.Btn.Def:hover,
	input.Btn.Def:focus,
	input.Btn.Def:active, 
	button.Btn.Def,
	button.Btn.Def:visited,
	button.Btn.Def:hover,
	button.Btn.Def:focus,
	button.Btn.Def:active 	{
		border: 1px solid #3165bd;
		/*filter:chroma(color=#000000);*/
		color: #ffffff;
		background-color: #3165bd;
		text-decoration: none;
		cursor: pointer;
		width: 90px;
		height: 28px;
		margin-left: 10px;
		/*outline: none;*/
	}

		input.Btn:disabled,
		input.Btn.Def:disabled,
		input.Btn[disabled=disabled],
		input.Btn.Def[disabled=disabled], 
		button.Btn:disabled,
		button.Btn.Def:disabled,
		button.Btn[disabled=disabled],
		button.Btn.Def[disabled=disabled] {
			color: #a6a6a6;
			border: 1px solid #dddddd;
		}

